fn matrix_multiply(a: &Vec<Vec<f64>>, b: &Vec<Vec<f64>>) -> Vec<Vec<f64>> {
    let rows = a.len();
    let cols = b[0].len();
    let inner = b.len();
    let mut result = vec![vec![0.0f64; cols]; rows];
    for i in 0..rows {
        for k in 0..inner {
            for j in 0..cols {
                result[i][j] += a[i][k] * b[k][j];
            }
        }
    }
    result
}
