Critique these two JavaScript event utilities:

```javascript
class EventEmitter {
  constructor() {
    this._listeners = new Map();
  }
  on(event, listener) {
    if (!this._listeners.has(event)) {
      this._listeners.set(event, []);
    }
    this._listeners.get(event).push(listener);
    return this;
  }
  emit(event, ...args) {
    const listeners = this._listeners.get(event) || [];
    listeners.forEach(fn => fn(...args));
    return this;
  }
  off(event, listener) {
    const list = this._listeners.get(event) || [];
    this._listeners.set(event, list.filter(fn => fn !== listener));
    return this;
  }
}
```

And the debounce utility:

```javascript
function debounce(fn, delayMs) {
  let timerId = null;
  return function debounced(...args) {
    if (timerId !== null) clearTimeout(timerId);
    timerId = setTimeout(() => {
      timerId = null;
      fn.apply(this, args);
    }, delayMs);
  };
}
```

