```python
def parse_csv(text: str, delimiter: str = ',') -> list:
    rows = []
    for line in text.strip().split('\n'):
        if not line.strip():
            continue
        fields = []
        current = ''
        in_quotes = False
        for ch in line:
            if ch == '"':
                in_quotes = not in_quotes
            elif ch == delimiter and not in_quotes:
                fields.append(current.strip())
                current = ''
            else:
                current += ch
        fields.append(current.strip())
        rows.append(fields)
    return rows
```

