def transform_records(rows: list, mapping: dict) -> list:
    if not rows:
        return []
    headers = rows[0]
    result = []
    for row in rows[1:]:
        record = {}
        for i, header in enumerate(headers):
            value = row[i] if i < len(row) else None
            key = mapping.get(header, header)
            record[key] = value
        result.append(record)
    return result
